mapper.select:
SELECT id, public_id::text AS publicKey, code, name, name_other AS nameOther, menu_group_code AS groupCode, menu_group_name AS groupName, menu_group_order AS groupOrderNo FROM module_types WHERE is_active = 1 AND EXISTS ( SELECT 1 FROM modules m JOIN module_details md ON md.module_id = m.id AND md.is_active = 1 WHERE m.module_type_id = module_types.id AND m.is_active = 1 )
AND name ILIKE '%' || #{searchText} || '%'
ORDER BY
${orderBy}
display_order ASC, id ASC
LIMIT #{rowsPerPage} OFFSET #{page}
